def get_pdf_page_text_raw(filepath: str, page_num: int) -> str:
    """Extract a single page's text — no Streamlit caching."""
    try:
        import pdfplumber
        with pdfplumber.open(filepath) as pdf:
            if 1 <= page_num <= len(pdf.pages):
                return pdf.pages[page_num - 1].extract_text() or ""
    except Exception as e:
        import logging
        logging.getLogger(__name__).error("Error extracting PDF page %d from %s: %s", page_num, filepath, e)
    return ""

